import { describe, it, expect } from 'vitest'
import { getApiError } from './utils'

describe('getApiError', () => {
  it('returns fallback for null', () => {
    expect(getApiError(null, 'fallback')).toBe('fallback')
  })

  it('returns fallback for non-object errors', () => {
    expect(getApiError('oops', 'fallback')).toBe('fallback')
    expect(getApiError(42, 'fallback')).toBe('fallback')
  })

  it('returns error field from ApiError', () => {
    expect(getApiError({ error: 'Invalid email' }, 'fallback')).toBe('Invalid email')
  })

  it('returns first item from errors array', () => {
    expect(getApiError({ errors: ['First error', 'Second'] }, 'fallback')).toBe('First error')
  })

  it('returns permission message for 403', () => {
    expect(getApiError({ status: 403 }, 'fallback')).toBe('You do not have permission to perform this action.')
  })

  it('returns server error message for 500', () => {
    expect(getApiError({ status: 500 }, 'fallback')).toBe('Server error. Please try again later.')
  })

  it('returns server error message for 503', () => {
    expect(getApiError({ status: 503 }, 'fallback')).toBe('Server error. Please try again later.')
  })

  it('403 message takes precedence over error field', () => {
    expect(getApiError({ status: 403, error: 'Custom' }, 'fallback')).toBe(
      'You do not have permission to perform this action.',
    )
  })

  it('uses error field for non-403/500 status', () => {
    expect(getApiError({ status: 422, error: 'Validation failed' }, 'fallback')).toBe('Validation failed')
  })

  it('returns fallback when object has no usable error info', () => {
    expect(getApiError({}, 'fallback')).toBe('fallback')
  })
})

