import { describe, it, expect, vi, beforeEach } from 'vitest'

function mockResponse(body: unknown, status = 200): Response {
  return {
    ok: status >= 200 && status < 300,
    status,
    json: vi.fn().mockResolvedValue(body),
  } as unknown as Response
}

const mockFetch = vi.fn()
vi.stubGlobal('fetch', mockFetch)

describe('api/client', () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let client: any

  beforeEach(async () => {
    vi.resetModules()
    mockFetch.mockReset()
    localStorage.clear()
    sessionStorage.clear()
    Object.defineProperty(window, 'location', {
      value: { href: '/', pathname: '/users', search: '?page=2' },
      writable: true,
      configurable: true,
    })
    const mod = await import('./client')
    client = mod.default
  })

  describe('request headers', () => {
    it('includes Authorization header when access_token is stored', async () => {
      localStorage.setItem('access_token', 'tok-123')
      mockFetch.mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.get('/api/v1/test')

      expect(mockFetch).toHaveBeenCalledWith(
        '/api/v1/test',
        expect.objectContaining({
          headers: expect.objectContaining({ Authorization: 'Bearer tok-123' }),
        }),
      )
    })

    it('omits Authorization header when no token stored', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.get('/api/v1/test')

      const [, options] = mockFetch.mock.calls[0]
      expect(options.headers).not.toHaveProperty('Authorization')
    })

    it('sets Content-Type application/json on every request', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.post('/api/v1/test', {})

      expect(mockFetch).toHaveBeenCalledWith(
        '/api/v1/test',
        expect.objectContaining({
          headers: expect.objectContaining({ 'Content-Type': 'application/json' }),
        }),
      )
    })
  })

  describe('request body', () => {
    it('serializes body to JSON for POST', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.post('/api/v1/auth/login', { email: 'a@b.com', password: 'pw' })

      const [, options] = mockFetch.mock.calls[0]
      expect(options.body).toBe(JSON.stringify({ email: 'a@b.com', password: 'pw' }))
    })

    it('sends no body for GET', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.get('/api/v1/test')

      const [, options] = mockFetch.mock.calls[0]
      expect(options.body).toBeUndefined()
    })
  })

  describe('response parsing', () => {
    it('returns { data } on successful response', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ users: [] }))

      const result = await client.get('/api/v1/users')

      expect(result).toEqual({ data: { users: [] } })
    })

    it('returns { data: {} } for 204 No Content without calling json', async () => {
      const jsonFn = vi.fn()
      mockFetch.mockResolvedValueOnce({ ok: true, status: 204, json: jsonFn } as unknown as Response)

      const result = await client.get('/api/v1/test')

      expect(result).toEqual({ data: {} })
      expect(jsonFn).not.toHaveBeenCalled()
    })

    it('rejects with error body and status code on non-ok response', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ error: 'Not found' }, 404))

      await expect(client.get('/api/v1/users')).rejects.toEqual({ error: 'Not found', status: 404 })
    })

    it('rejects with status only when error body is not valid JSON', async () => {
      mockFetch.mockResolvedValueOnce({
        ok: false,
        status: 500,
        json: vi.fn().mockRejectedValue(new SyntaxError('bad json')),
      } as unknown as Response)

      await expect(client.get('/api/v1/test')).rejects.toMatchObject({ status: 500 })
    })
  })

  describe('auth endpoints — 401 triggers no refresh', () => {
    it('rejects immediately on 401 from /auth/login', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ error: 'invalid credentials' }, 401))

      await expect(client.post('/api/v1/auth/login', {})).rejects.toBeDefined()
      expect(mockFetch).toHaveBeenCalledTimes(1)
    })

    it('rejects immediately on 401 from /auth/refresh', async () => {
      mockFetch.mockResolvedValueOnce(mockResponse({ error: 'expired' }, 401))

      await expect(client.post('/api/v1/auth/refresh', {})).rejects.toBeDefined()
      expect(mockFetch).toHaveBeenCalledTimes(1)
    })
  })

  describe('token refresh on 401', () => {
    it('refreshes token and retries original request', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'good-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ access_token: 'new-token' }))
        .mockResolvedValueOnce(mockResponse({ users: [] }))

      const result = await client.get('/api/v1/admin/users')

      expect(mockFetch).toHaveBeenCalledTimes(3)
      expect(result).toEqual({ data: { users: [] } })
    })

    it('stores new access token after successful refresh', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'good-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ access_token: 'new-token' }))
        .mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.get('/api/v1/admin/users')

      expect(localStorage.getItem('access_token')).toBe('new-token')
    })

    it('clears tokens when refresh request fails', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'bad-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ error: 'invalid' }, 401))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(localStorage.getItem('access_token')).toBeNull()
      expect(localStorage.getItem('refresh_token')).toBeNull()
    })

    it('clears tokens when no refresh token stored', async () => {
      localStorage.setItem('access_token', 'expired-token')

      mockFetch.mockResolvedValueOnce(mockResponse({}, 401))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(localStorage.getItem('access_token')).toBeNull()
    })

    it('clears tokens when refresh response is missing access_token', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'good-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ user: {} }))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(localStorage.getItem('access_token')).toBeNull()
      expect(localStorage.getItem('refresh_token')).toBeNull()
    })

    it('sets auth_expired flag in sessionStorage on token failure', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'bad-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ error: 'invalid' }, 401))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(sessionStorage.getItem('auth_expired')).toBe('1')
    })

    it('stores return_url in sessionStorage on token failure', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'bad-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ error: 'invalid' }, 401))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(sessionStorage.getItem('return_url')).toBe('/users?page=2')
    })
  })
})

