      mockFetch.mockResolvedValueOnce(mockResponse({ error: 'expired' }, 401))

      await expect(client.post('/api/v1/auth/refresh', {})).rejects.toBeDefined()
      expect(mockFetch).toHaveBeenCalledTimes(1)
    })
  })

  describe('token refresh on 401', () => {
    it('refreshes token and retries original request', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'good-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ access_token: 'new-token' }))
        .mockResolvedValueOnce(mockResponse({ users: [] }))

      const result = await client.get('/api/v1/admin/users')

      expect(mockFetch).toHaveBeenCalledTimes(3)
      expect(result).toEqual({ data: { users: [] } })
    })

    it('stores new access token after successful refresh', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'good-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ access_token: 'new-token' }))
        .mockResolvedValueOnce(mockResponse({ ok: true }))

      await client.get('/api/v1/admin/users')

      expect(localStorage.getItem('access_token')).toBe('new-token')
    })

    it('clears tokens when refresh request fails', async () => {
      localStorage.setItem('access_token', 'expired-token')
      localStorage.setItem('refresh_token', 'bad-refresh')

      mockFetch
        .mockResolvedValueOnce(mockResponse({}, 401))
        .mockResolvedValueOnce(mockResponse({ error: 'invalid' }, 401))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(localStorage.getItem('access_token')).toBeNull()
      expect(localStorage.getItem('refresh_token')).toBeNull()
    })

    it('clears tokens when no refresh token stored', async () => {
      localStorage.setItem('access_token', 'expired-token')

      mockFetch.mockResolvedValueOnce(mockResponse({}, 401))

      await expect(client.get('/api/v1/admin/users')).rejects.toBeDefined()

      expect(localStorage.getItem('access_token')).toBeNull()
    })
  })
})

