import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'
import { MemoryRouter } from 'react-router-dom'
import { ProtectedRoute } from './protected-route'
import { useAuth } from '@/hooks/use-auth'
import type { User } from '@/types/auth'

vi.mock('@/hooks/use-auth')
const mockUseAuth = vi.mocked(useAuth)

const mockUser: User = {
  id: '1',
  email: 'admin@test.com',
  role: 'admin',
  email_verified: true,
  created_at: '2024-01-01T00:00:00Z',
}

function renderRoute(children = <div>protected content</div>) {
  return render(
    <MemoryRouter>
      <ProtectedRoute>{children}</ProtectedRoute>
    </MemoryRouter>,
  )
}

describe('ProtectedRoute', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('shows loading spinner while auth is initializing', () => {
    mockUseAuth.mockReturnValue({ user: null, isLoading: true, login: vi.fn(), logout: vi.fn() })

    renderRoute()

    expect(screen.getByRole('status', { name: 'Loading' })).toBeInTheDocument()
    expect(screen.queryByText('protected content')).not.toBeInTheDocument()
  })

  it('renders children when user is authenticated', () => {
    mockUseAuth.mockReturnValue({
      user: mockUser,
      isLoading: false,
      login: vi.fn(),
      logout: vi.fn(),
    })

    renderRoute()

    expect(screen.getByText('protected content')).toBeInTheDocument()
  })

  it('does not render children when user is not authenticated', () => {
    mockUseAuth.mockReturnValue({ user: null, isLoading: false, login: vi.fn(), logout: vi.fn() })

    renderRoute()

    expect(screen.queryByText('protected content')).not.toBeInTheDocument()
  })
})

