import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, waitFor, within } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { UsersPage } from './users'
import { adminApi } from '@/api/admin'
import { toast } from 'sonner'
import type { AdminUser } from '@/types/auth'
import type { PaginationMeta } from '@/api/admin'
import React from 'react'

vi.mock('@/api/admin')
vi.mock('sonner', () => ({
  toast: { error: vi.fn(), success: vi.fn() },
}))
vi.mock('@/components/app-sidebar', () => ({
  AppSidebar: ({ children }: { children: React.ReactNode }) => <>{children}</>,
}))

const mockAdminApi = vi.mocked(adminApi)
const mockToast = vi.mocked(toast)

const activeUser: AdminUser = {
  id: '1',
  email: 'user@test.com',
  role: 'user',
  email_verified: true,
  deactivated: false,
  deactivated_at: null,
  created_at: '2024-01-15T00:00:00Z',
  updated_at: '2024-01-15T00:00:00Z',
}

const deactivatedUser: AdminUser = {
  id: '2',
  email: 'banned@test.com',
  role: 'user',
  email_verified: false,
  deactivated: true,
  deactivated_at: '2024-02-01T00:00:00Z',
  created_at: '2024-01-01T00:00:00Z',
  updated_at: '2024-02-01T00:00:00Z',
}

const defaultMeta: PaginationMeta = { total: 2, page: 1, per_page: 20 }

function makeListResponse(users: AdminUser[], meta = defaultMeta) {
  return { data: { users, meta } }
}

function renderPage() {
  return render(
    <MemoryRouter>
      <UsersPage />
    </MemoryRouter>,
  )
}

describe('UsersPage', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockAdminApi.listUsers.mockResolvedValue(makeListResponse([activeUser, deactivatedUser]))
    mockAdminApi.deactivateUser.mockResolvedValue({
      data: { message: 'ok', user: { ...activeUser, deactivated: true, deactivated_at: '2024-03-01' } },
    })
    mockAdminApi.activateUser.mockResolvedValue({
      data: { message: 'ok', user: { ...deactivatedUser, deactivated: false, deactivated_at: null } },
    })
  })

  describe('loading and error states', () => {
    it('shows loading spinner while fetching', () => {
      mockAdminApi.listUsers.mockReturnValueOnce(new Promise(() => {}))

      renderPage()

      expect(screen.getByText('Loading users...')).toBeInTheDocument()
    })

    it('renders user emails after load', async () => {
      renderPage()

      await waitFor(() => expect(screen.getByText('user@test.com')).toBeInTheDocument())
      expect(screen.getByText('banned@test.com')).toBeInTheDocument()
    })

    it('shows inline error banner when list users fails', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce(new Error('Network error'))

      renderPage()

      await waitFor(() =>
        expect(
          screen.getByText('Failed to load users. Check your connection and try again.'),
        ).toBeInTheDocument(),
      )
      expect(mockToast.error).not.toHaveBeenCalled()
    })

    it('shows permission denied message for 403 error', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce({ status: 403 })

      renderPage()

      await waitFor(() =>
        expect(screen.getByText('You do not have permission to perform this action.')).toBeInTheDocument(),
      )
    })

    it('shows server error message for 500 error', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce({ status: 500 })

      renderPage()

      await waitFor(() =>
        expect(screen.getByText('Server error. Please try again later.')).toBeInTheDocument(),
      )
    })

    it('retry button re-fetches users', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce(new Error('Network error'))
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser]))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Retry' }))
      await user.click(screen.getByRole('button', { name: 'Retry' }))

      await waitFor(() => expect(screen.getByText('user@test.com')).toBeInTheDocument())
      expect(mockAdminApi.listUsers).toHaveBeenCalledTimes(2)
    })
  })

  describe('table content', () => {
    it('shows Deactivate button for active users', async () => {
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      expect(screen.getByRole('button', { name: 'Deactivate user@test.com' })).toBeInTheDocument()
    })

    it('shows Activate button for deactivated users', async () => {
      renderPage()

      await waitFor(() => screen.getByText('banned@test.com'))
      expect(screen.getByRole('button', { name: 'Activate banned@test.com' })).toBeInTheDocument()
    })

    it('shows "No users found" for empty list', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([]))

      renderPage()

      await waitFor(() => expect(screen.getByText('No users found')).toBeInTheDocument())
    })

    it('formats date as YYYY-MM-DD', async () => {
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      expect(screen.getByText('2024-01-15')).toBeInTheDocument()
    })

    it('shows admin role badge in purple', async () => {
      const adminUser = { ...activeUser, role: 'admin' as const }
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([adminUser]))

      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      const badge = screen.getByText('admin')
      expect(badge.className).toContain('purple')
    })

    it('shows verified badge in green for verified users', async () => {
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      const verifiedBadge = screen.getByText('Verified')
      expect(verifiedBadge.className).toContain('green')
    })

    it('shows unverified badge for unverified users', async () => {
      renderPage()

      await waitFor(() => screen.getByText('banned@test.com'))
      expect(screen.getByText('Unverified')).toBeInTheDocument()
    })
  })

  describe('activate action', () => {
    it('calls activateUser and shows success toast', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('banned@test.com'))
      await user.click(screen.getByRole('button', { name: 'Activate banned@test.com' }))

      await waitFor(() => expect(mockAdminApi.activateUser).toHaveBeenCalledWith('2'))
      expect(mockToast.success).toHaveBeenCalledWith('banned@test.com activated')
    })

    it('shows error toast when activate fails with API error', async () => {
      mockAdminApi.activateUser.mockRejectedValueOnce({ error: 'User not found' })
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('banned@test.com'))
      await user.click(screen.getByRole('button', { name: 'Activate banned@test.com' }))

      await waitFor(() => expect(mockToast.error).toHaveBeenCalledWith('User not found'))
    })

    it('shows generic error toast when activate fails without message', async () => {
      mockAdminApi.activateUser.mockRejectedValueOnce(new Error())
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('banned@test.com'))
      await user.click(screen.getByRole('button', { name: 'Activate banned@test.com' }))

      await waitFor(() => expect(mockToast.error).toHaveBeenCalledWith('Failed to activate user'))
    })

    it('disables activate button while in progress', async () => {
      let resolveActivate!: () => void
      mockAdminApi.activateUser.mockReturnValueOnce(
        new Promise<{ data: { message: string; user: AdminUser } }>((res) => {
          resolveActivate = () => res({ data: { message: 'ok', user: { ...deactivatedUser, deactivated: false, deactivated_at: null } } })
        }),
      )
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('banned@test.com'))
      await user.click(screen.getByRole('button', { name: 'Activate banned@test.com' }))

      expect(screen.getByRole('button', { name: 'Activate banned@test.com' })).toBeDisabled()

      resolveActivate()
      await waitFor(() =>
        expect(screen.getByRole('button', { name: 'Activate banned@test.com' })).not.toBeDisabled(),
      )
    })
  })

  describe('deactivate confirmation dialog', () => {
    it('opens dialog when Deactivate button clicked', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      await user.click(screen.getByRole('button', { name: 'Deactivate user@test.com' }))

      expect(screen.getByText('Deactivate user?')).toBeInTheDocument()
    })

    it('dialog shows the user email', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      await user.click(screen.getByRole('button', { name: 'Deactivate user@test.com' }))

      await waitFor(() => {
        const dialog = screen.getByRole('alertdialog')
        expect(within(dialog).getByText('user@test.com')).toBeInTheDocument()
      })
    })

    it('Cancel closes dialog without calling API', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      await user.click(screen.getByRole('button', { name: 'Deactivate user@test.com' }))
      await waitFor(() => screen.getByText('Deactivate user?'))

      await user.click(screen.getByRole('button', { name: 'Cancel' }))

      await waitFor(() => expect(screen.queryByText('Deactivate user?')).not.toBeInTheDocument())
      expect(mockAdminApi.deactivateUser).not.toHaveBeenCalled()
    })

    it('Deactivate button in dialog calls deactivateUser', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      await user.click(screen.getByRole('button', { name: 'Deactivate user@test.com' }))
      await waitFor(() => screen.getByText('Deactivate user?'))

      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() => expect(mockAdminApi.deactivateUser).toHaveBeenCalledWith('1'))
    })

    it('dialog closes and shows success toast on successful deactivate', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByText('user@test.com'))
      await user.click(screen.getByRole('button', { name: 'Deactivate user@test.com' }))
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() => expect(screen.queryByText('Deactivate user?')).not.toBeInTheDocument())
      expect(mockToast.success).toHaveBeenCalledWith('user@test.com deactivated')
    })

    it('dialog stays open and shows inline error on deactivate failure', async () => {
