      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      expect(screen.getByRole('button', { name: 'Next' })).not.toBeDisabled()
    })

    it('clicking Next fetches next page', async () => {
      mockAdminApi.listUsers.mockResolvedValue(makeListResponse([activeUser], paginatedMeta))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      await user.click(screen.getByRole('button', { name: 'Next' }))

      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(2, 20, ''))
    })

    it('clicking Previous fetches previous page', async () => {
      const page2Meta: PaginationMeta = { total: 50, page: 2, per_page: 20 }
      mockAdminApi.listUsers
        .mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))
        .mockResolvedValueOnce(makeListResponse([activeUser], page2Meta))
        .mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      await user.click(screen.getByRole('button', { name: 'Next' }))
