    it('Next button disabled on last page', async () => {
      const lastPageMeta: PaginationMeta = { total: 40, page: 2, per_page: 20 }
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], lastPageMeta))

      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      expect(screen.getByRole('button', { name: 'Next' })).toBeDisabled()
    })

    it('shows current page of total pages', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      renderPage()

      await waitFor(() => screen.getByText('Page 1 of 3'))
